import{_ as e,o as r,c as a,ag as o}from"./chunks/framework.OsDJF_Ea.js";const c=JSON.parse('{"title":"Flashing Firmware","description":"","frontmatter":{},"headers":[],"relativePath":"getting-started/flashing-firmware.md","filePath":"getting-started/flashing-firmware.md"}'),i={name:"getting-started/flashing-firmware.md"};function l(n,t,s,h,d,p){return r(),a("div",null,[...t[0]||(t[0]=[o('<h1 id="flashing-firmware" tabindex="-1">Flashing Firmware <a class="header-anchor" href="#flashing-firmware" aria-label="Permalink to &quot;Flashing Firmware&quot;">​</a></h1><p>The Smart Contact Mic firmware runs on the ESP32-S3. You can flash it directly from the patcher app in your browser -- no Arduino IDE or other tools needed.</p><h2 id="before-you-start" tabindex="-1">Before You Start <a class="header-anchor" href="#before-you-start" aria-label="Permalink to &quot;Before You Start&quot;">​</a></h2><ul><li>Use a <strong>data-capable USB-C cable</strong> (charge-only cables won&#39;t work)</li><li>Use <strong>Chrome or Edge</strong> on desktop (Web Serial is not supported in Firefox or Safari)</li><li>Close any other app that might be using the serial port (Arduino IDE, PlatformIO, serial monitors)</li></ul><h2 id="first-time-flash-new-board" tabindex="-1">First-Time Flash (New Board) <a class="header-anchor" href="#first-time-flash-new-board" aria-label="Permalink to &quot;First-Time Flash (New Board)&quot;">​</a></h2><p>If your board has never been flashed, or you need to recover from a bad state:</p><ol><li><strong>Hold the BOOT button</strong> on the ESP32-S3 board</li><li>While holding BOOT, <strong>plug in the USB cable</strong> (or press RESET if already plugged in)</li><li>Release BOOT -- the board is now in bootloader mode</li><li>Open the patcher at <a href="https://soniphorm.com/app/" target="_blank" rel="noreferrer">soniphorm.com/app</a></li><li>Click the <strong>firmware update</strong> button in the toolbar (chip icon)</li><li>Select the latest firmware version from the dropdown</li><li>Click <strong>Flash</strong> and select the serial port when prompted</li><li>Wait for the flash to complete (approximately 30 seconds)</li><li>Press the <strong>RESET</strong> button on the board</li></ol><h2 id="updating-firmware" tabindex="-1">Updating Firmware <a class="header-anchor" href="#updating-firmware" aria-label="Permalink to &quot;Updating Firmware&quot;">​</a></h2><p>If your board already has a working firmware:</p><ol><li>Open the patcher and connect to your board (see <a href="/docs/getting-started/connecting.html">Connecting</a>)</li><li>Click the <strong>firmware update</strong> button in the toolbar</li><li>Select the new version and click <strong>Flash</strong></li><li>The board will restart automatically after flashing</li><li>You may need to press <strong>RESET</strong> once after the flash completes</li></ol><h2 id="troubleshooting" tabindex="-1">Troubleshooting <a class="header-anchor" href="#troubleshooting" aria-label="Permalink to &quot;Troubleshooting&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Problem</th><th>Solution</th></tr></thead><tbody><tr><td>No serial port appears</td><td>Check your USB cable is data-capable. Try a different port. Close other serial apps.</td></tr><tr><td>Flash fails immediately</td><td>Put the board in bootloader mode (hold BOOT + press RESET).</td></tr><tr><td>Board doesn&#39;t respond after flash</td><td>Press the RESET button. If still unresponsive, reflash in bootloader mode.</td></tr><tr><td>&quot;Port is already in use&quot;</td><td>Close Arduino IDE, PlatformIO, or any serial terminal that might be connected.</td></tr></tbody></table><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>After flashing, the board sometimes needs a manual press of the RESET button before it will enumerate on USB. This is a known quirk of the ESP32-S3.</p></div>',13)])])}const m=e(i,[["render",l]]);export{c as __pageData,m as default};
